import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirPatientActions } from '../../../actions';
import { MyChart } from '../../../../utils';
import { monthLabels } from '../../../../../../utils';
import { hirUtil } from '../../../../utils';


const style = theme => ({
    root: {
    }
})
class _HIRPatientYearlyAppointments extends Component {
    constructor(props) {
        super(props);
        props.getContext(this);
    }
    static async getData(year, patientId, dispatch, callback) {
        let result;
        try{
            result = await hirPatientActions.getPatientYearlyAppointments(patientId, year)(dispatch)
            if(callback) callback(null, result);
        }catch(message){
            result = message;
            if(callback) callback(message)
        }
        return result;
    }
    deriveMonthlyData(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            const value = data.find(item=>item._id.month==i+1);
            if(value){
                returnData.push(value[valueName]);
            }else returnData.push(0);
        }
        return returnData;
    }
    render() {
        const {classes, year, data} = this.props;
        return (
            <MyChart
                canvasId="patientYearlyAppointments"
                title={"Monthly Appointments "+year}
                labels={monthLabels}
                datasets={[{
                    label: 'Total amount',
                    data : this.deriveMonthlyData(data, "count"),                                
                    backgroundColor : hirUtil.getTheme().primaryTrans,
                    borderColor : hirUtil.getTheme().primary,
                }]}
            />
        );
    }
}


_HIRPatientYearlyAppointments.propTypes = {
    classes : PropTypes.object.isRequired,
    patientId : PropTypes.number,
    year : PropTypes.number,
};
export const HIRPatientYearlyAppointments = connect()(withStyles(style)(_HIRPatientYearlyAppointments));
export {HIRPatientYearlyAppointments as default}