import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Button, Grid } from '@material-ui/core';
import { AccountBalance, AccountBalanceWallet } from '@material-ui/icons';
import { HIRButton } from '../../../Includes';
import { appActions, errorNotice, hirUtil } from '../../../utils';


const style = theme => ({
    root: {
        borderRadius : 20,
        background : theme.colors.background,
        padding : 20,
    },
    creditWallet : {
        display : "flex",
    },
    refund : {
        marginTop : 20, fontSize : 12, color : "red",
        cursor : "pointer",
    }
})
class _HIRPatientCreditDebit extends Component {
    _refund(patientId, credit){
        const {dispatch, refund} = this.props;
        if(credit === 0) return errorNotice("Patient credit is zero (0), nothing to refund!", dispatch);
        appActions.showSnackDialog(
            "Sure! You want to refund this credit?",
            [<Button key="refundPayment" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                refund && refund({patientId, credit})
            }}>Continue</Button>]
        )(dispatch);
    }
    render() {
        const {classes, patient} = this.props,
        {credit, debt} = patient || {},
        patientId = patient?._id;
        return (
            <div className={classes.root}>
                <Grid container>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.creditWallet}>
                            <div style={{width : "30%", borderRight : "solid 1px", display : "flex", justifyContent : "flex-end", padding : 10}}>
                                <AccountBalanceWallet/>
                            </div>
                            <div style={{padding : 10, display : "flex", flexDirection : "column"}}>
                                <strong>Credit</strong>
                                <span>{Number(credit || 0).toLocaleString()}</span>
                                {hirUtil.isAdmin() && !debt && <u className={classes.refund} onClick={() => this._refund(patientId, credit)}>
                                    Refund
                                </u>}
                            </div>
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.creditWallet}>
                            <div style={{width : "30%", borderRight : "solid 1px", display : "flex", justifyContent : "flex-end", padding : 10}}>
                                <AccountBalance/>
                            </div>
                            <div style={{padding : 10, display : "flex", flexDirection : "column"}}>
                                <strong>Debts</strong>
                                <span>{Number(debt || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </Grid>
                </Grid>                
            </div>
        );
    }
}


_HIRPatientCreditDebit.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    refund : PropTypes.func,
};


export const HIRPatientCreditDebit = connect()(withStyles(style)(_HIRPatientCreditDebit));
export {HIRPatientCreditDebit as default}