import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {Fab, Grid, Typography} from '@material-ui/core';
import { hirPatientStrings } from '../../config';
import { Edit } from '@material-ui/icons';
import { hirUtil } from '../../../utils';
import { SimpleListBoard, MyListCard } from '../../../utils';
import { patientNameMapper } from '../../patientNameMapper';
import { hirSettingStrings, hirSettingActions } from '../../../HIRSettings';


const style = theme => ({
    root : {},
    fab : {},
    icon :{},
    listRoot : {
        backgroundColor : "transparent",
    },
    headerContainer : {
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
    },
    header : {
        fontWeight : "bold",
        color : hirUtil.getTheme().primary1,
    },
    itemContainer : {
        display : "flex",
        width : "100%",
        marginTop : 10,
    },
    item : {
        width : "50%",
        fontSize : 11,
    }
})
class _HIRGeneralInfo extends Component {
    componentDidMount() {
        const {dispatch, [hirSettingStrings.settings] : settings} = this.props;
        if(!settings) hirSettingActions.getSettings()(dispatch);
    }
    
    listComponent(item){
        const {classes} = this.props;
        return <div className={classes.itemContainer}>
            <div className={classes.item}>
                <strong>{patientNameMapper(item.name)}</strong> : 
            </div>
            <div className={classes.item}>
                {patientNameMapper(item.value)}
            </div>
        </div>
    }
    getUnitName(settings, unit){
        let unitValue = unit;
        if(settings) {
            const units = settings.find(item=>item.name === "units");
            if(units && units.values){
                unitValue = units.values.find(item=>item.name === unit).value;
            }
        }
        return unitValue;
    }
    render() {
        const {
            classes, patientInfo, fabOnClick, lastNextAppointment,
            [hirSettingStrings.settings] : settings
        } = this.props;
        const {last, next} = lastNextAppointment
        if(!patientInfo) return null;
        return (
            <div className={classes.root}>
                <div className={classes.headerContainer}>
                    <Typography paragraph className={classes.header}>
                        PID {String(patientInfo._id).padStart(6, "0")}
                        {patientInfo.myProfile && patientInfo.myProfile.oldId && " ("+patientInfo.myProfile.oldId+")"}
                    </Typography>
                </div>
                <Grid container spacing={2}>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>
                        <MyListCard 
                            classes={{root : classes.listRoot}}
                            list={Object.entries(patientInfo.myProfile).map(item=>({name : item[0], value : item[1]}))}
                            elevation={0}
                            component={this.listComponent.bind(this)}
                        />
                    </Grid>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>   
                        <MyListCard 
                            classes={{root : classes.listRoot}}
                            list={[
                                {name : "Last Appointment", value : last && new Date(last.date).toLocaleDateString()}, 
                                {name : "Last Appointment Unit", value : last && this.getUnitName(settings, last.unit)}, 
                                {name : "Next Appointment", value : next && new Date(next.date).toLocaleDateString()},
                                {name : "Next Appointment Unit", value : next && this.getUnitName(settings, next.unit)}, 
                            ]}
                            elevation={0}
                            component={this.listComponent.bind(this)}
                            />                     
                    </Grid>
                    <Grid item xs={12} sm={6} md={4} lg={4} xl={4}>                        
                    </Grid>
                </Grid>                
                <Fab className={classes.fab} 
                    size="small" 
                    onClick={fabOnClick}>
                    <Edit className={classes.icon}/>
                </Fab>
            </div>
        );
    }
}


_HIRGeneralInfo.propTypes = {
    classes : PropTypes.object.isRequired, 
    patientInfo : PropTypes.object,
    lastNextAppointment : PropTypes.object,
    fabOnClick : PropTypes.func,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings]
})


export const HIRGeneralInfo = connect(mapStateToProps)(withStyles(style)(_HIRGeneralInfo));
export {HIRGeneralInfo as default}