import React, { useState } from 'react'
import PropTypes from 'prop-types'
import { useDispatch, useSelector } from 'react-redux'
import { FormLabel, Grid, makeStyles, Popover } from '@material-ui/core'
import { Add } from '@material-ui/icons'
import { HIRPatientViewClinicList } from './HIRPatientViewClinicList'
import { errorNotice } from '../../../utils'
import { hirPatientActions } from '../../actions'
import { hirSettingNames, hirSettingStrings } from '../../../HIRSettings'
const style = makeStyles(theme => ({
    root: {
        borderRadius : 20,
        background : theme.colors.background,
        padding : 20,
    },
    addClinic : {
        fontSize : 12, display : "flex", alignItems : "center",
        cursor : "pointer",
        "&:hover" : {
            color : theme.colors.secondary
        }
    },
    paper : {
        backgroundColor : theme.colors.primary,
        color : theme.colors.white,
    },
    clinic : {
        fontSize : 12,
        color : theme.colors.secondary,
    },
    id : {
        fontSize : 14,
        fontWeight : "bold",
    }
}))
function HIRPatientViewClinics({patient, updatePatient, ...props}) {
    const dispatch = useDispatch(),
    classes = style(),
    {clinics : patientClinics} = patient || {},
    [state, _setState] = useState({
        anchorEl : null,
    }),
    setState = (_state, callback) => _setState(state=>({...state, ..._state}), callback),
    {
        anchorEl
    } = state,
    {hirSettingReducer} = useSelector(state=>state),
    {
        [hirSettingStrings.settings] : settings
    } = hirSettingReducer,
    clinicSettings = settings && settings.find(item=>item.name === hirSettingNames.CLINICS),
    clinics = clinicSettings?.values,
    createClinicPatient = clinic => {
        setState({anchorEl : null});
        const {name : clinicName} = clinic || {};
        if(!clinicName) return errorNotice("Clinic not selected!", dispatch);
        const patientId = patient?._id;
        if(!patientId) return errorNotice("Patient ID not properly retrieved!", dispatch);
        const data = {patientId, clinicName}
        hirPatientActions.createClinicPatient(data, done => {
            done && updatePatient && updatePatient({updateHeader : false});
        })(dispatch);
    }
    const unRegisteredClinics = [];
    if(clinics) for (let i = 0; i < clinics.length; i++) {
        const {name} = clinics[i];
        if(!patientClinics || !patientClinics.find(item=>item.clinicName === name))
            unRegisteredClinics.push(clinics[i]);
    }
    return (
        <div className={classes.root}>
            <FormLabel>
                <div style={{display : "flex", justifyContent : "space-between"}}>
                    <span>Clinics</span>
                    {unRegisteredClinics.length > 0 && <u className={classes.addClinic} onClick={({target : anchorEl}) => setState({anchorEl})}>
                        <Add fontSize="small"/>
                        Add to clinics
                    </u>}
                    <Popover
                        classes={{
                            paper : classes.paper
                        }}
                        anchorOrigin={{
                            horizontal : "left"
                        }}
                        anchorEl={anchorEl}
                        open={Boolean(anchorEl)}
                        onClose={() => setState({anchorEl : null})}
                    >
                        <HIRPatientViewClinicList
                            clinics={unRegisteredClinics}
                            onSelect={createClinicPatient}
                        />
                    </Popover>
                </div>
            </FormLabel>
            <small>Generate clinic IDs</small>
            <div style={{marginTop : 20}}>
                <Grid container>
                {patientClinics && patientClinics.map((item, index)=>{
                    const {clinicName, code, prefix} = item,
                    clinic = clinics && clinics.find(i=>i.name===clinicName);
                    return <Grid item xs={12} sm={6} md={4} lg={4} xl={4} key={index}>
                        <div className={classes.clinicRow}>
                            <div className={classes.clinic}>{clinic?.value}</div>
                            <div className={classes.id}>{prefix + String(code).padStart(6, "0")}</div>
                        </div>
                    </Grid>
                })}
                </Grid>
            </div>
        </div>
    )
}
HIRPatientViewClinics.propTypes = {
    
}
export default HIRPatientViewClinics;
export {HIRPatientViewClinics};