import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirAccountActions } from '../../../HIRAccounts';
import { appActions, errorNotice, hirUtil, MyDialog, MyTable, SimplePagination, simplePaginationConfig } from '../../../utils';
import { Button, Fab, IconButton, Menu, MenuItem, TableCell } from '@material-ui/core';
import { Add, Delete, Edit } from '@material-ui/icons';
import { HIRNewDeposit } from '../../../HIRDeposits/HIRNewDeposit';


const style = theme => ({
    root: {
        padding : 20,
        background : theme.colors.background,
        borderRadius : 20,
    },
    tableWrapper : {
        maxHeight : "10cm"
    },
    table : {
        backgroundColor : "transparent",
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    fab : {
        
    },
    icon : {

    },
    iconBtn : {
        padding : 2.5
    }
})
class _HIRPatientDeposit extends Component {
    state = {
        openDialog : false,
    }
    componentDidMount() {
        this.depositConfig();
    }
    depositConfig(callback){
        this.pageControl = simplePaginationConfig(
            this, this.getDeposits, this.props.dispatch,
            "deposits", 50, null, null, this.getDepositMinMaxIds,
            this.searchDeposits, this.getSearchDepositMinMaxIds
        )
        this.setState({keyword : ""});
        this.pageControl.getAction(callback);
    }
    getFilter(){
        const {patientId} = this.props;
        return {patientId};
    }
    getDeposits = (rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getDeposits(filter, rows, skip, sort, max, callback)(dispatch);
    }
    getDepositMinMaxIds = (sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getDepositMinMaxIds(filter, sort, callback)(dispatch);
    }
    searchDeposits = (keyword, rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.searchDeposits(filter, keyword, rows, skip, sort, max, callback)(dispatch);
    }
    getSearchDepositMinMaxIds = (keyword, sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getSearchDepositMinMaxIds(filter, keyword, sort, callback)(dispatch);
    }
    cellMapFormat({row, cellMap}){
        const {classes} = this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                <div style={{display : "flex"}}>
                    <IconButton className={classes.iconBtn} onClick={()=>this.setState({openDialog : true, deposit : row})}>
                        <Edit fontSize="small"/>
                    </IconButton>
                    <IconButton className={classes.iconBtn} onClick={()=>this.deleteDeposit(row)}>
                        <Delete fontSize="small" color="secondary"/>
                    </IconButton>
                </div>
            </TableCell>
            case "actionDate" : return <TableCell className={classes.cell}>
                {row[cellMap] && new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            default: return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    closeDialog = ()=>this.setState({openDialog : false});
    createDeposit(data, callback) {
        const {dispatch, patientId, updatePatient} = this.props;
        if(!patientId) return errorNotice("There is no patient selected", dispatch);
        hirAccountActions.createDeposit({...data, patientId}, done => {
            callback && callback(done);
            if(done){
                this.closeDialog();
                this.depositConfig();
                updatePatient && updatePatient({updateHeader : false})
            }
        })(dispatch);
    }
    onUpdateDeposit(data, callback) {
        const {dispatch, updatePatient} = this.props,
        {deposit} = this.state,
        {_id : depositId} = deposit || {};
        if(!depositId) return errorNotice("There is no patient selected", dispatch);
        hirAccountActions.updateDeposit(depositId, data, done => {
            callback && callback(done);
            if(done){
                this.closeDialog();
                this.depositConfig();
                updatePatient && updatePatient({updateHeader : false})
            }
        })(dispatch);
    }
    deleteDeposit(deposit){
        const {dispatch, updatePatient} = this.props;
        appActions.showSnackDialog(
            "Sure! You want to delete this deposit? This will affect accounts",
            [<Button key="deleteDeposit" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                hirAccountActions.deleteDeposit(deposit && deposit._id, done => {
                    if(done){
                        this.depositConfig();
                        updatePatient && updatePatient({updateHeader : false})
                    }
                })(dispatch);
            }}>Continue</Button>]
        )(dispatch);
    }
    render() {
        const {classes} = this.props,
        {deposits, openDialog, deposit} = this.state,
        header = ["Amount", "Description", "Date"],
        dataMap = ["amount", "description", "actionDate"];
        if(hirUtil.isAdmin()){
            header.push("Actions");
            dataMap.push("action");
        }
        return (
            <div className={classes.root}>
                <MyTable
                    classes={{root : classes.table, tableWrapper : classes.tableWrapper}}
                    elevation={0}
                    title="Deposits"
                    header={header}
                    dataMap={dataMap}
                    data={deposits}
                    CellMap={this.cellMapFormat.bind(this)}
                />
                {this.pageControl && deposits && deposits.length > 0 && <div style={{marginTop : 20}}>
                        <SimplePagination
                            iconButton
                            nextBtnClick={this.pageControl.nextBtnOnClick()}
                            nextBtnProps={{
                                disabled : this.pageControl.nextBtnDisabled()
                            }}
                            prevBtnClick={this.pageControl.prevBtnOnClick()}
                            prevBtnProps={{
                                disabled : this.pageControl.prevBtnDisabled()
                            }}
                            />
                    </div>}
                <Fab
                    onClick={()=>this.setState({openDialog : true})}
                    className={classes.fab} size="small">
                    <Add className={classes.icon}/>
                </Fab>
                <MyDialog
                    open={openDialog}
                    close={this.closeDialog.bind(this)}
                    data={deposit}
                    onCancel={this.closeDialog.bind(this)}
                    onEdit={Boolean(deposit)}
                    onUpdateDeposit={this.onUpdateDeposit.bind(this)}
                >
                    <HIRNewDeposit
                        onCreateDeposit={this.createDeposit.bind(this)}
                    />
                </MyDialog>
            </div>
        );
    }
}


_HIRPatientDeposit.propTypes = {
    classes : PropTypes.object.isRequired,
    patientId : PropTypes.number,
    patient : PropTypes.object,
    updatePatient : PropTypes.func,
};


export const HIRPatientDeposit = connect()(withStyles(style)(_HIRPatientDeposit));
export {HIRPatientDeposit as default}