import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Grid } from '@material-ui/core';
import { HIRPatientYearlyPayments } from './HIRPatientYearlyPayments';
import { HIRPatientYearlyAppointments } from './HIRPatientYearlyAppointments';
import { DateController } from './DateController';
import { HIRPatientFamilyMembers } from './HIRPatientFamilyMembers.js/HIRPatientFamilyMembers';


const style = theme => ({
    root: {
        padding : 10
    }
})
class _HIRPatientStatistics extends Component {
    render() {
        const {classes, patientId, familyId} = this.props;
        return (
            <div className={classes.root}>
                <Grid style={{height : 300}} container spacing={2}>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <DateController
                            component={HIRPatientYearlyPayments}
                            patientId={patientId}/>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <DateController
                            component={HIRPatientYearlyAppointments}
                            patientId={patientId}/>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <HIRPatientFamilyMembers
                            patientId={patientId}
                            familyId={familyId}/>
                    </Grid>
                </Grid>
            </div>
        );
    }
}


_HIRPatientStatistics.propTypes = {
    classes : PropTypes.object.isRequired,
    patientId : PropTypes.number,
    familyId : PropTypes.number,
};
export const HIRPatientStatistics = connect()(withStyles(style)(_HIRPatientStatistics));
export {HIRPatientStatistics as default}